import openpyxl
from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
from openpyxl.utils import get_column_letter

wb = openpyxl.Workbook()

# 스타일 정의
title_font = Font(name='맑은 고딕', bold=True, size=14, color='FFFFFF')
header_font = Font(name='맑은 고딕', bold=True, size=10, color='FFFFFF')
cell_font = Font(name='맑은 고딕', size=10)
title_fill = PatternFill(start_color='1a1a2e', end_color='1a1a2e', fill_type='solid')
header_fill = PatternFill(start_color='2d2d5e', end_color='2d2d5e', fill_type='solid')
sub_fill = PatternFill(start_color='3d3d7e', end_color='3d3d7e', fill_type='solid')
alt_fill = PatternFill(start_color='f0f0f8', end_color='f0f0f8', fill_type='solid')
gold_font = Font(name='맑은 고딕', bold=True, size=10, color='FFD700')
red_font = Font(name='맑은 고딕', bold=True, size=10, color='FF4444')
green_font = Font(name='맑은 고딕', bold=True, size=10, color='22AA22')
thin_border = Border(
    left=Side(style='thin', color='CCCCCC'),
    right=Side(style='thin', color='CCCCCC'),
    top=Side(style='thin', color='CCCCCC'),
    bottom=Side(style='thin', color='CCCCCC')
)

def style_sheet(ws, headers, data, title=None, col_widths=None):
    row = 1
    if title:
        ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=len(headers))
        c = ws.cell(row=1, column=1, value=title)
        c.font = title_font; c.fill = title_fill; c.alignment = Alignment(horizontal='center')
        row = 3
    for ci, h in enumerate(headers, 1):
        c = ws.cell(row=row, column=ci, value=h)
        c.font = header_font; c.fill = header_fill; c.alignment = Alignment(horizontal='center', wrap_text=True)
        c.border = thin_border
    row += 1
    for ri, d in enumerate(data):
        for ci, v in enumerate(d, 1):
            c = ws.cell(row=row+ri, column=ci, value=v)
            c.font = cell_font; c.border = thin_border
            c.alignment = Alignment(horizontal='center', vertical='center', wrap_text=True)
            if ri % 2 == 1: c.fill = alt_fill
    if col_widths:
        for i, w in enumerate(col_widths, 1):
            ws.column_dimensions[get_column_letter(i)].width = w

