    ('시간 마법사', 3, 42, 10, 170),
    # Grade 4 전설
    ('공허의 왕', 4, 65, 20, 400),
    ('세계수 정령', 4, 25, 30, 600),
    ('세라핌', 4, 35, 25, 400),
    ('죽음의 기사', 4, 55, 35, 500),
    ('천상의 기사', 4, 60, 40, 550),
    ('혼돈의 군주', 4, 62, 22, 420),
