# ========== 서버 이벤트 달력 (1개월 상세) ==========
ws_event = wb.create_sheet('서버 이벤트 달력 1개월')
event_headers = ['일', '요일', '오전 이벤트', '오후 이벤트', '저녁 이벤트', '특별 이벤트', '보상 총합']
day_names = ['월', '화', '수', '목', '금', '토', '일']
morning_pool = [
    '골드 러시 (채굴 2배)', '무역 보너스 (수익 +30%)', '경험치 폭풍 (EXP 2배)',
    '포획 확률 UP (+15%)', '합성 할인 (-20% 골드)', '무료 가챠 1회', '연구 가속 (시간 -30%)',
    '용병 훈련소 개방', '정원 수확 2배', '낚시 대회 (오전부)'
]
afternoon_pool = [
    '아레나 시즌전', 'IO 랭크 매치 2배 점수', '레이드 보스 출현', '심연의 탑 도전',
    '무역 카라반 호위전', 'PvP 토너먼트 예선', '몬스터 웨이브 방어전',
    '보스 러시 (연속 5체)', '차원의 균열 개방', '혈맹 미션 (오후부)'
]
evening_pool = [
    '공성전 연습', '야간 PvP (PK 페널티 감소)', '월드 보스 (서버 협동)',
    '비밀 던전 개방', '혈맹 대전 리그', '야간 무역 (밀수 루트)',
    '별빛 낚시 (희귀 물고기)', '몬스터 야행성 포획', '심야 경매장 할인', '스토리 퀘스트 개방'
]
event_data = []
for day in range(1, 31):
    dow = day_names[(day - 1) % 7]
    mi = (day - 1) % len(morning_pool)
    ai = (day + 2) % len(afternoon_pool)
    ei = (day + 1) % len(evening_pool)
    morning = morning_pool[mi]
    afternoon = afternoon_pool[ai]
    evening = evening_pool[ei]

    special = '-'
    gold = 3000 + (day * 100)
    dia = 30

    if dow == '토':
        special = '🏆 포획대회 + 보스러시 (종일)'
        gold += 5000; dia += 50
    elif dow == '일':
        special = '⚔️ 혈맹 공성전 (15:00~21:00)'
        gold += 8000; dia += 80
    elif day <= 3:
        special = '🎉 시즌 개막 이벤트 (로그인 보상 3배)'
        gold += 3000; dia += 30
    elif 14 <= day <= 16:
        special = '🔥 중간 결산 이벤트 (랭킹 보상 2배)'
        gold += 4000; dia += 40
    elif day >= 28:
        special = '🏁 시즌 마감 이벤트 (최종 랭킹 보상)'
        gold += 6000; dia += 60
    elif day == 10:
        special = '🎁 10일 연속 출석 보상 (전설 가챠 1회)'
        dia += 100
    elif day == 20:
        special = '🎁 20일 연속 출석 보상 (선택 용병 상자)'
        dia += 100
    elif dow == '금':
        special = '🌙 금요일 야간 특별전 (22:00~02:00)'
        gold += 2000; dia += 20

    reward = f'{gold:,}G + {dia}💎'
    event_data.append([day, dow, morning, afternoon, evening, special, reward])

style_sheet(ws_event, event_headers, event_data,
            title='서버 이벤트 달력 — 1개월(30일) 상세 스케줄',
            col_widths=[6, 6, 26, 26, 26, 36, 18])

