# ========== 배틀패스 Lv1~50 상세 보상표 ==========
ws_bp = wb.create_sheet('배틀패스 Lv1~50 보상표')
bp_headers = ['Lv', '필요 EXP', '무료 보상', '유료 보상', '누적 EXP', '누적 무료 골드', '누적 유료 다이아']
bp_data = []
cum_exp = 0
cum_gold = 0
cum_dia = 0
for lv in range(1, 51):
    need_exp = 100 + (lv - 1) * 200
    cum_exp += need_exp
    if lv == 50:
        free_reward = '20,000G'
        paid_reward = '신화 용병 교환권'
        cum_gold += 20000
    elif lv % 10 == 0:
        free_reward = f'{lv * 100}G + 용병 카드 팩 x2'
        paid_reward = f'전설 스킨 선택권 + 다이아 {lv * 5}'
        cum_gold += lv * 100
        cum_dia += lv * 5
    elif lv % 5 == 0:
        free_reward = f'각성석 x{lv // 5} + {lv * 80}G'
        paid_reward = f'용병 카드 팩 + 다이아 {lv * 3}'
        cum_gold += lv * 80
        cum_dia += lv * 3
    elif lv % 2 == 0:
        gold_amt = 500 + (lv - 2) * 187
        free_reward = f'{gold_amt:,}G'
        paid_reward = f'다이아 {lv * 2}'
        cum_gold += gold_amt
        cum_dia += lv * 2
    else:
        free_reward = f'강화석 x{lv // 3 + 1}'
        paid_reward = f'HP 물약(대) x{lv // 2 + 1} + 다이아 {lv}'
        cum_dia += lv
    bp_data.append([lv, need_exp, free_reward, paid_reward, cum_exp,
                     f'{cum_gold:,}G', f'{cum_dia} 다이아'])
style_sheet(ws_bp, bp_headers, bp_data,
            title='배틀패스 Lv1~50 상세 보상표',
            col_widths=[8, 12, 28, 30, 12, 18, 18])

